import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Report } from '../../core/models';
import { AdminApiService } from '../../core/services/admin-api.service';

@Component({
  selector: 'app-reports',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './reports.component.html',
  styleUrl: './reports.component.css',
})
export class ReportsComponent implements OnInit {
  private admin = inject(AdminApiService);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly reports = signal<Report[]>([]);
  readonly filter = signal<'pending' | 'all'>('pending');

  readonly pendingCount = computed(() => this.reports().filter((r) => r.status === 'pending').length);
  readonly visible = computed(() =>
    this.filter() === 'pending' ? this.reports().filter((r) => r.status === 'pending') : this.reports(),
  );

  ngOnInit(): void {
    // Filter is URL-addressable via ?filter=pending|all so the view is deep-linkable.
    const q = this.route.snapshot.queryParamMap.get('filter');
    this.filter.set(q === 'all' ? 'all' : 'pending');

    this.admin.reports().subscribe({
      next: (reports) => this.reports.set(reports ?? []),
      error: () => this.reports.set([]),
    });
  }

  setFilter(f: 'pending' | 'all'): void {
    this.filter.set(f);
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { filter: f },
      queryParamsHandling: 'merge',
    });
  }
}
